  ('locality-0c700c30-moex-00094', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設政府對於某商品的買方課徵每單位1元的稅，則下列敘述何者錯誤？', '["若課稅的對象變為該商品的賣方，所造成的影響相同", "在課稅後，買方價格高於賣方價格，故市場會有超額供給", "與未課稅時的市場均衡相較下，課稅後市場均衡數量可能下降", "若供給有彈性，需求無彈性，則稅主要由買方負擔 31560、31960 32060"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00095', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '當咖啡及茶所提供的咖啡因相同時，小丁對消費此兩種財貨的滿足程度就相同。假設一杯咖啡所 提供的咖啡因為一杯茶的2倍。以茶的數量為縱軸，咖啡的數量為橫軸。下列何者為小丁的無異 曲線？', '["斜率為-2的直線", "斜率為-1/2的直線", "水平線", "L型的曲線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00096', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '一位消費者的消費組合中包含A和B兩種商品。假設該消費者收入並未改變，面對商品A的價 格上升，下列敘述何者正確？', '["由於消費者收入並未改變，不會形成所得效果", "如果商品A是正常財，所得效果和替代效果對於商品A的消費量會有同向的影響", "如果商品B是劣等財，所得效果和替代效果對於商品B的消費量會有反向的影響", "假設現在商品B的價格同時下降，則其會放大商品A價格上升所帶來的所得效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00097', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '有關廠商的生產與成本，下列敘述何者錯誤？', '["當邊際產量高於平均產量，平均產量遞增", "當邊際成本高於平均成本，平均成本遞減", "當邊際產量上升時，邊際成本下降", "邊際成本線會通過平均變動成本線的最低點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00098', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設商品A市場目前由一廠商獨占供給，但存在另一潛在進入廠商。對此情勢，下列敘述何者 正確？', '["消費者會希望潛在廠商不要進入市場，延續獨占的市場局面", "消費者會希望潛在廠商進入市場，兩家廠商並形成「卡特爾（cartel）」聯盟，一同決定產量與 價格", "消費者會希望潛在廠商進入市場，兩家廠商形成Cournot模型中的競爭模式", "消費者會希望潛在廠商進入市場，兩家廠商形成Stackelberg模型中的競爭模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00099', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', 'X和Y兩間競爭公司，有生產A商品或B商品兩種生產策略。X和Y兩間公司同時決策所對應 的利潤如下圖（括弧中數字，左項為X公司的利潤，右項為Y公司的利潤），則下列有關此賽局 的Nash均衡何者正確？', '["X和Y都生產A商品", "X和Y都生產B商品", "X生產A商品、Y生產B商品", "X生產B商品、Y生產A商品 31560、31960 32060"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00100', 'locality-0c700c30', 'locality-0c700c30-moex-112-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設最低工資高於市場均衡工資，如果政府調升最低工資，則：', '["勞動供給量上升", "勞動需求量上升", "社會福利一定上升", "勞動需求量大於勞動供給量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:14+00:00", "source_pdf_sha1": "876ca4244349", "answer_pdf_sha1": "494374bd7a58", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "315", "s": "1502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
